<template>
  <v-container fluid fill-height>
    <v-row class="fill-height" justify="center" align="center">
      <v-col cols="12" sm="8" md="6">
        <v-card outlined elevated>
          <v-card-text>
            <v-card-title>Login</v-card-title>
            <v-form @submit.prevent="handleSubmit">
              <v-text-field 
                v-model="username" 
                label="Username" 
                required 
                type="text"
                color="cyan"
                variant="solo"
              />
              <v-text-field 
                v-model="password" 
                label="Password" 
                required 
                type="password" 
                color="cyan"
                variant="solo"
              />
              <v-btn type="submit" color="primary">Login</v-btn>
            </v-form>
          </v-card-text>
        </v-card>
      </v-col>
    </v-row>
    <v-snackbar v-model="snackbar" :timeout="3000" color="success">
      {{ snackbarMessage }}
      <v-btn text @click="snackbar = false">Close</v-btn>
    </v-snackbar>
  </v-container>
</template>


<script>
import { useRouter } from 'vue-router';
import { useStore } from 'vuex';
import { ref } from 'vue';

export default {
  name: 'LogIn',
  setup() {
    const router = useRouter();
    const store = useStore();

    // Reactive data properties
    const username = ref('');
    const password = ref('');
    const snackbar = ref(false);
    const snackbarMessage = ref('');

    // Methods
    const handleSubmit = async () => {
  console.log('handleSubmit called');
  try {
    const apiUrl = process.env.VUE_APP_API_URL || '/api';
    const response = await fetch(`${apiUrl}/users/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username: username.value, password: password.value }),
    });

    const data = await response.json();

    if (response.ok) {
      console.log('API Response Data:', data);
      console.log('User data from API:', data.user);

      // Store user information in localStorage
      localStorage.setItem('username', username.value);
      localStorage.setItem('jwtToken', data.token);

      // Dispatch user data to Vuex
      console.log('Dispatching to Vuex setUser action:', data.user);
      store.dispatch('setUser', data.user);

      // Navigate to the appropriate page
      if (data.firstLogin) {
        console.log('User is logging in for the first time');
        router.replace({ name: 'welcomePage' });
      } else if (data.user.role === 'Admin') {
        router.replace({ name: 'adminDashboard' });
      } else {
        router.replace({ name: 'selectCategory' });
      }
    } else {
      // Handle invalid credentials
      snackbarMessage.value = 'Invalid username or password';
      snackbar.value = true;
    }
  } catch (error) {
    console.error('Error during login:', error);
    // Handle server error
    snackbarMessage.value = 'Server error';
    snackbar.value = true;
  }

  // Clear input fields after submission
  username.value = '';
  password.value = '';
};


    return {
      username,
      password,
      snackbar,
      snackbarMessage,
      handleSubmit,
    };
  },
};
</script>

